// 1. Access the incoming search results
// We use a fallback empty array to prevent "undefined" errors
const results = items[0].json.results || []; 

// 2. Optimized cleaning function
const cleanText = (text) => {
  if (!text) return "";
  return text
    .replace(/<[^>]*>?/gm, '')    // Strip HTML tags
    .replace(/[\r\n\t]+/g, ' ')  // Replace newlines and tabs with a single space
    .replace(/\s\s+/g, ' ')      // Collapse multiple spaces
    .replace(/[^\x20-\x7E]/g, '') // Remove non-printable/special characters
    .trim();
};

const cleanedData = results.slice(0, 3).map(item => {
  let title = (item.title || "Source").substring(0, 40);
  let snippet = cleanText(item.content || item.snippet || "");

  const LIMIT = 500; // Increased slightly for better context

  if (snippet.length > LIMIT) {
    // Find the last period before the limit to avoid cutting mid-sentence
    const lastPeriod = snippet.lastIndexOf('.', LIMIT);
    if (lastPeriod > 100) { // Only cut at period if it's not too short
      snippet = snippet.substring(0, lastPeriod + 1);
    } else {
      snippet = snippet.substring(0, LIMIT) + "...";
    }
  }

  return `[${title}]: ${snippet}`;
});

return [{
  json: {
    cleaned_search_context: cleanedData.join(' | ').replaceAll("\"", "\'")
  }
}];

